{"code":"import json
import re

# Load business data
file_path = locals()['var_function-call-363388082624961722']
with open(file_path, 'r') as f:
    businesses = json.load(f)

state_counts = {}
state_businesses = {} # State -> list of business_ids

# Regex for State: " in [City], [State], this"
state_pattern = re.compile(r" in [^,]+, ([A-Z]{2}), this")
# Special case: "This Philadelphia, PA location..." -> "This [City], [State] location"
# Pattern 2 for description starting with "This ..."
state_pattern_2 = re.compile(r"This [^,]+, ([A-Z]{2}) location")

for b in businesses:
    attrs = b.get('attributes')
    desc = b.get('description', '')

    # Check WiFi
    has_wifi = False
    if attrs and isinstance(attrs, dict):
        wifi_val = attrs.get('WiFi')
        if wifi_val:
            wifi_str = str(wifi_val).lower()
            if 'free' in wifi_str or 'paid' in wifi_str:
                has_wifi = True

    if has_wifi:
        # Extract State
        state = None
        match = state_pattern.search(desc)
        if match:
            state = match.group(1)
        else:
            match2 = state_pattern_2.search(desc)
            if match2:
                state = match2.group(1)

        if state:
            state_counts[state] = state_counts.get(state, 0) + 1
            if state not in state_businesses:
                state_businesses[state] = []
            state_businesses[state].append(b['business_id'])

# Find top state
if not state_counts:
    result = {"top_state": None, "count": 0, "ids": []}
else:
    top_state = max(state_counts, key=state_counts.get)
    top_count = state_counts[top_state]
    top_ids = state_businesses[top_state]
    result = {"top_state": top_state, "count": top_count, "ids": top_ids}

print("__RESULT__:")
print(json.dumps(result))"}

